let backgroundImgBase64 = "data:image/jpeg;base64,";
let img;

function preload() {
  img = loadImage(backgroundImgBase64);
}


function setup() {
  createCanvas(windowWidth, windowHeight);
  imageMode(CENTER);

  image(img, windowWidth/2, 2*windowHeight/3, img.width, img.height);
}

// function draw() {
  
// }

function windowResized() {
  resizeCanvas(windowWidth, windowHeight);
  image(img, windowWidth/2, 2*windowHeight/3, img.width, img.height);
}